mapper.select:
SELECT mu.uid, u.nickname,u.avatar,u.sex,u.phone, mm.level,usc.recharge_amount,usc.gift_amount,mm.financial_status,mm.create_time as membershipTime, mml.name as levelName, IFNULL(umc.uid, 0) as isCollect FROM eb_merchant_user AS mu LEFT JOIN eb_user u on u.id = mu.uid LEFT JOIN eb_user_merchant_collect umc on mu.uid = umc.uid and mu.mer_id = umc.mer_id LEFT JOIN eb_merchant_member mm on mu.uid = mm.uid and mu.mer_id = mm.mer_id and mm.is_logoff = 0 LEFT JOIN eb_merchant_member_level mml on mml.level = mm.level and mu.mer_id = mml.mer_id and mml.is_del = 0 LEFT JOIN eb_user_shopping_credits usc on usc.uid = mu.uid and usc.mer_id = mu.mer_id WHERE mu.mer_id = #{merId} and u.is_logoff = 0
and umc.uid is not null
and mm.id is not null
and mm.level = #{memberLevel}
and mm.financial_status = #{financialStatus}
and u.sex = #{sex}
and mm.create_time between #{startTime} and #{endTime}
and ( u.id like CONCAT('%',#{keywords},'%') or u.nickname like CONCAT('%',#{keywords},'%') or u.phone like CONCAT('%',#{keywords},'%') )
and u.id = #{uid}
and u.nickname like CONCAT('%',#{nickname},'%')
and u.phone like CONCAT('%',#{phone},'%')
ORDER BY mu.id desc
